# Build JSON payload
payload = {
    "mnq": {},
    "factors": {"ES": {}, "YM": {}, "RTY": {}, "ZN": {}, "GC": {}}
}

for row in MNQ_BARS:
    ts, o, h, l, c, v = row
    payload["mnq"][str(ts)] = {"open": o, "high": h, "low": l, "close": c, "volume": v}

for ts, c in ES_CLOSES:
    payload["factors"]["ES"][str(ts)] = c

for ts, c in YM_CLOSES:
    payload["factors"]["YM"][str(ts)] = c

for ts, c in RTY_CLOSES:
    payload["factors"]["RTY"][str(ts)] = c

for ts, c in ZN_CLOSES:
    payload["factors"]["ZN"][str(ts)] = c

for ts, c in GC_CLOSES:
    payload["factors"]["GC"][str(ts)] = c

out_path = os.path.join(os.path.dirname(__file__), "bars.json")
with open(out_path, "w") as f:
    json.dump(payload, f)

print(f"Written {out_path}")
print(f"MNQ bars: {len(payload['mnq'])}")
for sym, d in payload['factors'].items():
    print(f"{sym} closes: {len(d)}")
